using System.Net;
using System.Windows.Forms;
class ImageLoader
{
    void LoadImage(PictureBox pictureBox, string url)
    {
        try { pictureBox.Load(url); }
        catch (WebException ex) { Console.WriteLine("Failed: " + ex.Message); }
    }
}

arguments.new_str:
using System;
using System.Net.Http;
using System.Threading.Tasks;
using System.Windows.Forms;

class ImageLoader
{
    void LoadImage(PictureBox pictureBox, string url)
    {
        // .NET 9: PictureBox now throws HttpRequestException/TaskCanceledException
        // instead of WebException when loading from URLs fails.
        try { pictureBox.Load(url); }
        catch (HttpRequestException ex) { Console.WriteLine("Failed: " + ex.Message); }
        catch (TaskCanceledException ex) { Console.WriteLine("Timed out: " + ex.Message); }
    }
}

